patch:
diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
index 9a16ca96db76..87a4f86f5849 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
@@ -993,6 +993,18 @@ Instruction *InstCombinerImpl::foldAddWithConstant(BinaryOperator &Add) {
     }
   }

+
+  // add (zext nneg (add nsw X, C1)), C2 --> add (sext X, C1 + C2)
+  // add (sext (add nsw X, C1)), C2 --> add (sext X, C1 + C2)
+  const APInt *InnerC;
+  if (match(Op0, m_OneUse(m_SExtLike(m_NSWAdd(m_Value(X), m_APInt(InnerC)))))) {
+    APInt Combined = InnerC->sext(Ty->getScalarSizeInBits()) + *C;
+    if (Combined.isZero())
+      return CastInst::Create(Instruction::SExt, X, Ty);
+    Value *Sext = Builder.CreateSExt(X, Ty);
+    return BinaryOperator::CreateAdd(Sext, ConstantInt::get(Ty, Combined));
+  }
+
   return nullptr;
 }

